import{_ as o,o as r,c as t,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"7. Hours Of Work","description":"","frontmatter":{"title":"7. Hours Of Work","eba":"Health Allied & Managers Admin 2021-2025","topics":["leave","hours","shift-work","employment"]},"headers":[],"relativePath":"ebas/has-managers-admin/managers-admin/hours-of-work/7-hours-of-work.md","filePath":"ebas/has-managers-admin/managers-admin/hours-of-work/7-hours-of-work.md"}'),s={name:"ebas/has-managers-admin/managers-admin/hours-of-work/7-hours-of-work.md"};function n(i,e,h,u,p,l){return r(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="_7-hours-of-work" tabindex="-1">7. Hours Of Work <a class="header-anchor" href="#_7-hours-of-work" aria-label="Permalink to &quot;7. Hours Of Work&quot;">​</a></h1><p><strong>7.1</strong> The ordinary hours of work for a full-time Employee will be 38 hours, or an average of 38 hours, per week in a fortnight or 4 week period.</p><p><strong>7.2</strong> For the purposes of subclause 7.1, the ordinary hours an Employee works in a week are taken to include any hours of authorised leave, or absence, whether paid or unpaid, that the Employee takes in a week.</p><p><strong>7.3</strong> The working week will commence at midnight on a Sunday.</p><p><strong>7.4</strong> Notwithstanding any authorised meal breaks or rest breaks, the work of each day/shift will be continuous.</p><p><strong>7.5</strong> 12-hour shifts</p><p><strong>(a)</strong> 12-hour shifts may be performed by mutual agreement between the Employee and Employer provided that:</p><p><strong>(i)</strong> The Employer must notify the HWU of any requests to engage an Employee on 12-hour shift arrangements and consult where requested;</p><p><strong>(ii)</strong> The Employer must monitor the Employee in accordance with the Work-Related Fatigue Clause at Section 1, clause 78.2; and</p><p><strong>(iii)</strong> The Employer must ensure that an Employee working 12-hour shifts will not be paid any less than the relevant Modern Award entitlement.</p><p><strong>(iv)</strong> The Employee must be provided 10 consecutive hours off duty after each 12-hour shift, otherwise Overtime rates apply for each hour worked until the 10 consecutive hours off duty is provided.</p><p>Plain language terms: ordinary hours, weekly hours.</p>',12)])])}const f=o(s,[["render",n]]);export{d as __pageData,f as default};
